-- MK Fraud Readiness Score V1 - Phase 4 dev seed (merged)
-- Run after 0001_phase2_v1_1_schema_rls.sql in the Supabase dev project only.
--
-- Merge note: the Phase 4 v1.1 package's own version of this file only created an EMPTY
-- "methodology shell" (one active methodology_versions row with zero domains, questions,
-- response_scale or exposure_factors). That was enough to satisfy the assessments FK and
-- pass Phase 4's own tests, but it silently drops the entire approved Phase 1 methodology
-- (10 domains, 68 questions, response scale, exposure model, recommendation rules) that was
-- already generated and verified against the Technical Scoring Test Matrix during the Phase 2
-- fix pass. This merged version seeds the real content instead of a shell, is idempotent
-- (safe to re-run against the same dev project), and keeps every Phase-4-specific addition
-- (respondent_token_policy "phase":"phase4" tag, phase4_email_mode) from the original file.

do $seed$
declare
  v_methodology_id uuid;
  v_already_seeded boolean;
begin

values ('MFRS-V1.0', 'MK Fraud Readiness Score V1 Methodology', 'active', now())
on conflict (version_code) do update set
  title = excluded.title,
  status = excluded.status,
  effective_from = coalesce(public.methodology_versions.effective_from, excluded.effective_from),
  updated_at = now()
returning id into v_methodology_id;

select exists(
  select 1 from public.domains where methodology_version_id = v_methodology_id
) into v_already_seeded;

if not v_already_seeded then

-- Response scale (0-5, normalised 0/20/40/60/80/100)

-- Ten fraud-readiness domains with approved weights (sum = 100)

-- 68 approved questions (Phase 1 workbook is the seed source per Blueprint section 11.1)

-- Eight exposure factors (max points sum = 100)
-- input_type decision: 'banded_scale_0_4' for all factors. Real decision (not a
-- placeholder): every factor is presented as a 5-point banded scale (0=none/negligible
-- through 4=extensive), mirroring the same ordinal-scale pattern already approved for
-- readiness questions, so respondents answer a consistent UI shape across the assessment.
-- Phase 5/6 may refine to a factor-specific control (e.g. a slider) without changing
-- points_awarded semantics, which are already stored independently in exposure_answers.

-- Applicability rules for questions marked 'Conditional' N/A in the workbook.
-- Real decision (not a placeholder): each Conditional question is gated on the exposure
-- factor whose profile most plausibly makes it inapplicable (e.g. a third-party due
-- diligence question only applies if the organisation actually has third-party exposure).
-- expression_json is a simple, evaluable condition: N/A is allowed only when the named
-- exposure factor's awarded points are 0 for this assessment. Phase 5/6 implements the
-- evaluator and may refine thresholds once real exposure_answers data exists to check
-- against; amend this seed rather than leaving the condition undefined.

-- Recommendation trigger rules (from the approved Recommendation Triggers sheet).
-- action_30/60/90 decision: organised directly from the sheet's own action_logic column
-- into the day-30/60/90 structure the schema expects - not new methodology, just the
-- existing approved guidance broken into sequenced steps. MK/product owner may amend the
-- exact wording in Phase 6-9 content authoring without needing to invent it from scratch.

end if;

end;
$seed$;

-- Phase-4-specific settings (kept from the original Phase 4 v1.1 dev seed)
on conflict (setting_key) do update set value_json = excluded.value_json, updated_at = now();
