insert into public.question_applicability_rules (question_id, rule_key, expression_json)
values
  ((select id from public.questions where methodology_version_id = v_methodology_id and question_code = 'D2-Q05'), 'd2-q05_na_rule', '{"condition_type": "exposure_factor_threshold", "exposure_factor_code": "EXP-02", "operator": "<=", "threshold": 0, "rationale": "Only applicable if the organisation has third-party, supplier or intermediary relationships."}'::jsonb),
  ((select id from public.questions where methodology_version_id = v_methodology_id and question_code = 'D2-Q08'), 'd2-q08_na_rule', '{"condition_type": "exposure_factor_threshold", "exposure_factor_code": "EXP-03", "operator": "<=", "threshold": 0, "rationale": "Only applicable if the organisation has customer-facing digital channels, platforms or loyalty/service ecosystems."}'::jsonb),
  ((select id from public.questions where methodology_version_id = v_methodology_id and question_code = 'D3-Q05'), 'd3-q05_na_rule', '{"condition_type": "exposure_factor_threshold", "exposure_factor_code": "EXP-07", "operator": "<=", "threshold": 0, "rationale": "Only applicable if the organisation performs manual interventions such as refunds, credits or manual adjustments."}'::jsonb),
  ((select id from public.questions where methodology_version_id = v_methodology_id and question_code = 'D3-Q07'), 'd3-q07_na_rule', '{"condition_type": "exposure_factor_threshold", "exposure_factor_code": "EXP-01", "operator": "<=", "threshold": 0, "rationale": "Only applicable if the organisation has high-risk operational processes with individuals in high-risk roles."}'::jsonb),
  ((select id from public.questions where methodology_version_id = v_methodology_id and question_code = 'D6-Q05'), 'd6-q05_na_rule', '{"condition_type": "exposure_factor_threshold", "exposure_factor_code": "EXP-02", "operator": "<=", "threshold": 0, "rationale": "Only applicable if the organisation has external stakeholders (suppliers, contractors, customers) who could use a whistleblowing channel."}'::jsonb),
  ((select id from public.questions where methodology_version_id = v_methodology_id and question_code = 'D7-Q05'), 'd7-q05_na_rule', '{"condition_type": "exposure_factor_threshold", "exposure_factor_code": "EXP-02", "operator": "<=", "threshold": 0, "rationale": "Only applicable if the organisation has high-risk suppliers or third-party relationships to monitor."}'::jsonb),
  ((select id from public.questions where methodology_version_id = v_methodology_id and question_code = 'D7-Q07'), 'd7-q07_na_rule', '{"condition_type": "exposure_factor_threshold", "exposure_factor_code": "EXP-02", "operator": "<=", "threshold": 0, "rationale": "Only applicable if the organisation enters partnerships, distribution arrangements or intermediary relationships."}'::jsonb),
  ((select id from public.questions where methodology_version_id = v_methodology_id and question_code = 'D8-Q01'), 'd8-q01_na_rule', '{"condition_type": "exposure_factor_threshold", "exposure_factor_code": "EXP-04", "operator": "<=", "threshold": 0, "rationale": "Only applicable if the organisation verifies identity of customers, users or counterparties."}'::jsonb),
  ((select id from public.questions where methodology_version_id = v_methodology_id and question_code = 'D8-Q02'), 'd8-q02_na_rule', '{"condition_type": "exposure_factor_threshold", "exposure_factor_code": "EXP-03", "operator": "<=", "threshold": 0, "rationale": "Only applicable if the organisation has digital platforms/systems with login or account access to monitor."}'::jsonb),
  ((select id from public.questions where methodology_version_id = v_methodology_id and question_code = 'D8-Q05'), 'd8-q05_na_rule', '{"condition_type": "exposure_factor_threshold", "exposure_factor_code": "EXP-03", "operator": "<=", "threshold": 0, "rationale": "Only applicable if the organisation has digital channels where misuse or unauthorised transactions could occur."}'::jsonb),
  ((select id from public.questions where methodology_version_id = v_methodology_id and question_code = 'D8-Q08'), 'd8-q08_na_rule', '{"condition_type": "exposure_factor_threshold", "exposure_factor_code": "EXP-04", "operator": "<=", "threshold": 0, "rationale": "Only applicable if the organisation handles identity data where misuse, takeover or impersonation risk exists."}'::jsonb);
insert into public.recommendation_rules (methodology_version_id, rule_code, trigger_type, condition_json, severity, title, body, action_30, action_60, action_90, sort_order)
values
  (v_methodology_id, 'REC-01', 'workbook_trigger', '{"trigger_text": "Domain score <=39"}'::jsonb, 'Critical priority', 'Domain score <=39', 'Immediate MK review recommended; build basic ownership, controls and response foundations before relying on the score as mature.', 'Assign named executive ownership and begin an emergency baseline review of the domain''s core controls.', 'Document minimum viable controls, close any hard-gate critical gaps, and establish a basic monitoring routine.', 'Confirm baseline controls are operating consistently and schedule a follow-up MK review to re-assess maturity.', 1),
  (v_methodology_id, 'REC-02', 'workbook_trigger', '{"trigger_text": "Domain score 40-59"}'::jsonb, 'Improvement priority', 'Domain score 40-59', 'Formalise ownership, document controls, improve consistency and introduce review rhythm within 30-60 days.', 'Formalise ownership and document existing controls and processes for the domain.', 'Improve consistency of control operation across the organisation and introduce a regular review rhythm.', 'Evidence the improved controls have operated consistently for at least one full cycle and identify remaining gaps.', 2),
  (v_methodology_id, 'REC-03', 'workbook_trigger', '{"trigger_text": "Domain score 60-79"}'::jsonb, 'Strengthening priority', 'Domain score 60-79', 'Improve evidence, monitoring, escalation, analytics and cross-functional operating rhythm.', 'Review current evidence, monitoring and escalation practices for gaps.', 'Introduce or improve analytics/monitoring coverage and clarify escalation authority.', 'Establish a cross-functional operating rhythm and confirm sustained improvement with fresh evidence.', 3),
  (v_methodology_id, 'REC-04', 'workbook_trigger', '{"trigger_text": "Domain score >=80"}'::jsonb, 'Maintain and improve', 'Domain score >=80', 'Protect the capability through periodic testing, control refresh and leadership reporting.', 'Confirm current controls remain documented and owned.', 'Schedule periodic testing and a control refresh cycle.', 'Report control performance to leadership and confirm no drift has occurred.', 4),
  (v_methodology_id, 'REC-05', 'workbook_trigger', '{"trigger_text": "Any hard-gate critical control <=1"}'::jsonb, 'Maturity cap', 'Any hard-gate critical control <=1', 'Overall maturity cannot exceed Developing; include critical gap section in report.', 'Treat the failed hard-gate control as an urgent priority and assign an executive owner.', 'Implement a minimum viable version of the control and remove the immediate critical gap.', 'Confirm the control is operating and request a recalculation to determine if the cap can be lifted.', 5),
  (v_methodology_id, 'REC-06', 'workbook_trigger', '{"trigger_text": "Any hard-gate critical control =2"}'::jsonb, 'Maturity cap', 'Any hard-gate critical control =2', 'Overall maturity cannot exceed Structured; include remediation action in 30/60/90 plan.', 'Confirm what evidence is missing for the control to be considered consistently operating.', 'Close the evidence or consistency gap and document the control operation.', 'Request a recalculation once the control can be evidenced as consistently operating (response 3 or higher).', 6),
  (v_methodology_id, 'REC-07', 'workbook_trigger', '{"trigger_text": "Three or more critical controls <=2"}'::jsonb, 'Maturity cap', 'Three or more critical controls <=2', 'Overall maturity cannot exceed Developing regardless of weighted score.', 'Prioritise the critical controls with the lowest responses across all domains.', 'Close as many of the critical gaps as possible and document interim compensating measures for the rest.', 'Reduce the critical-gap count to below three and request a recalculation.', 7),
  (v_methodology_id, 'REC-08', 'workbook_trigger', '{"trigger_text": "Assessment coverage <80%"}'::jsonb, 'Invalid / incomplete', 'Assessment coverage <80%', 'Do not issue score; ask respondent to complete missing sections.', 'Identify which sections of the assessment remain incomplete.', 'Complete the outstanding sections with the correct respondent(s).', 'Resubmit the assessment once coverage reaches at least 80%.', 8),
  (v_methodology_id, 'REC-09', 'workbook_trigger', '{"trigger_text": "Assessment coverage 80-89%"}'::jsonb, 'Provisional score', 'Assessment coverage 80-89%', 'Show coverage warning and recommend MK review before report release.', 'Review the coverage warning and identify which sections were left incomplete or marked N/A.', 'Complete any sections that can reasonably be answered to raise coverage above 90%.', 'Request an MK review of the provisional score before relying on it for reporting.', 9),
  (v_methodology_id, 'REC-10', 'workbook_trigger', '{"trigger_text": "N/A rate >20%"}'::jsonb, 'Review flag', 'N/A rate >20%', 'Admin review required to ensure N/A selections are justified and not inflating the score.', 'MK reviews the N/A selections to confirm they are genuinely not applicable.', 'Where an N/A was used as a default rather than a genuine exemption, ask the respondent to provide a real answer.', 'Confirm the corrected N/A rate is below 20% before releasing a paid report.', 10);
